INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b0dda57-7eaa-485b-bd75-9942fb31ad14',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte Forms — bind:value vs Uncontrolled Fields, and Superforms + Zod$escape$,
  $escape$React's controlled vs uncontrolled distinction doesn't map cleanly to Svelte. `bind:value` is two-way binding by default — there's no `useState` overhead, no synthetic event wiring. 'Uncontrolled' in Svelte means reading from `FormData` directly in a `+page.server.ts` action, skipping reactive state entirely. That's the right call for simple forms: let the browser own the DOM, parse on submit.

For complex forms with validation, `sveltekit-superforms` + Zod is the idiomatic Svelte equivalent of React Hook Form + Zod. Define a Zod schema once, run `superValidate` on the server in both `load` and the action, then call `superForm(data.form)` in your component. It returns a `$form` store (bound to inputs), an `$errors` store (per-field Zod messages), and an `enhance` action that handles progressive enhancement. No client-side schema duplication — the same Zod schema validates on both sides. Constraint API (`$constraints`) auto-populates `min`, `maxlength`, and `required` attributes, cutting boilerplate further.$escape$,
  $escape$// +page.server.ts
import { superValidate, fail } from 'sveltekit-superforms';
import { zod } from 'sveltekit-superforms/adapters';
import { z } from 'zod';

const schema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
});

export const load = async () => ({ form: await superValidate(zod(schema)) });

export const actions = {
  default: async ({ request }) => {
    const form = await superValidate(request, zod(schema));
    if (!form.valid) return fail(400, { form });
    return { form };
  },
};$escape$,
  $escape$typescript$escape$,
