INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'be38607b-225f-4c1a-b1b1-07a5ad886fff',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte Testing — Test What Users See, Not How Signals Work$escape$,
  $escape$Most Svelte component tests fail the wrong way: they assert on internal `$state` values or implementation details that users never interact with. The Testing Library philosophy flips this — query the DOM the way a user would, not through component internals.

With `@testing-library/svelte`, avoid reaching into component instances or inspecting reactive variables directly. Instead, query by role, label, or text: `getByRole('button', { name: /submit/i })` is robust to refactors; `component.loading` is not.

This matters in Svelte 5 especially. Runes (`$state`, `$derived`) are implementation details. If you refactor from `$derived` to a `$effect` that writes to `$state`, your UI behavior shouldn't change — and your tests shouldn't break if they're written correctly.

Fire real DOM events with `fireEvent` or `userEvent`, then assert on rendered output: visible text, ARIA state, disabled attributes. A button becoming disabled after a click is observable behavior. The boolean that caused it is not. Write tests that would still pass after a complete internal rewrite.$escape$,
  $escape$import { render, screen, fireEvent } from '@testing-library/svelte';
import Counter from './Counter.svelte';

test('increments count on click', async () => {
  render(Counter);

  const button = screen.getByRole('button', { name: /increment/i });
  const display = screen.getByText(/count: 0/i);

  await fireEvent.click(button);

  // Assert DOM output — not component.$state.count
  expect(screen.getByText(/count: 1/i)).toBeInTheDocument();
});$escape$,
  $escape$javascript$escape$,
