INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cfe2e8ed-9877-48c0-9ba3-7310e9d13bfd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte Bundle Optimization — Tree-Shaking, Lazy Loading, and Bundle Analysis$escape$,
  $escape$Svelte's compiler already eliminates unused component code at build time, but you still need to be deliberate about what ends up in your initial bundle. For heavy components — rich text editors, chart libraries, code highlighters — use dynamic imports with `{#await}` to defer loading until needed. Vite's `rollupOptions.output.manualChunks` lets you split vendor dependencies into separate chunks, keeping your entry bundle lean. To analyze what's actually shipping, install `rollup-plugin-visualizer` and add it to your `vite.config.ts` plugins array — it generates an interactive treemap of every module. For component-level lazy loading, wrap dynamic imports in a loading state using Svelte's `{#await}` block rather than reaching for a third-party suspense abstraction. Also audit your `$lib` barrel files — re-exporting everything from an `index.ts` can defeat tree-shaking if bundlers can't statically analyze the exports. Prefer direct imports (`import Chart from '$lib/Chart.svelte'`) over barrel re-exports for large, infrequently used components.$escape$,
  $escape$// vite.config.ts
import { sveltekit } from '@sveltejs/kit/vite';
import { visualizer } from 'rollup-plugin-visualizer';

export default {
  plugins: [
    sveltekit(),
    visualizer({ open: true, filename: 'bundle-stats.html' })
  ],
  build: {
    rollupOptions: {
      output: {
        manualChunks: { vendor: ['chart.js', 'codemirror'] }
      }
    }
  }
};

<!-- HeavyComponent.svelte usage -->
<script>
  const Editor = import('$lib/RichTextEditor.svelte');
</script>
{#await Editor}
  <p>Loading editor…</p>
{:then { default: Editor }}
  <svelte:component this={Editor} />
{/await}$escape$,
  $escape$typescript$escape$,
